function WorkspaceAside({ pages, collaborators, children, comments }) {
  const { div, aside, main, header, span, nav, section } = tags;
  const [navCollapsed, setNavCollapsed] = createSignal(false);
  const [asideCollapsed, setAsideCollapsed] = createSignal(false);

  return div({ class: css('_grid _h[100vh]'), style: () => `grid-template-columns:${navCollapsed() ? '48px' : '240px'} 1fr ${asideCollapsed() ? '0' : '280px'};grid-template-rows:52px 1fr` },
    // Page tree sidebar
    aside({ class: css('_flex _col _bgmuted _borderR'), style: 'grid-row:1/3' },
      div({ class: css('_flex _aic _jcsb _p3 _borderB') },
        !navCollapsed() ? span({ class: css('_heading5') }, 'Pages') : null,
        Button({ variant: 'ghost', size: 'sm', onclick: () => setNavCollapsed(!navCollapsed()) },
          icon('panel-left')
        )
      ),
      nav({ class: css('_flex _col _gap1 _p2 _flex1 _overflow[auto]') },
        ...pages.map(p =>
          link({ href: `/doc/${p.id}`, class: css('_flex _aic _gap2 _p2 _r2 _trans') },
            span({ class: css('_text[1.25em]') }, p.icon),
            !navCollapsed() ? span({ class: css('_truncate') }, p.title) : null
          )
        )
      ),
      div({ class: css('_p2 _borderT') },
        Button({ variant: 'outline', class: css('_wfull') },
          icon('plus'), !navCollapsed() ? ' New Page' : null
        )
      )
    ),
    // Header with presence
    header({ class: css('_flex _aic _jcsb _px6 _py3 _borderB _bgbg'), style: 'grid-column:2/4' },
      span({ class: css('_heading4') }, 'Document'),
      div({ class: css('_flex _aic _gap4') },
        Button({ variant: 'outline', size: 'sm' }, icon('share'), ' Share'),
        div({ class: css('_flex _aic _-ml2') },
          ...collaborators.slice(0, 4).map((c, i) =>
            Avatar({ src: c.avatar, size: 'sm', class: css(`_ring2 _ring[${c.color}] _ml[-8px]`) })
          ),
          collaborators.length > 4 ? span({ class: css('_textsm _fgmuted _ml2') }, `+${collaborators.length - 4}`) : null
        ),
        Button({ variant: 'ghost', size: 'sm' }, icon('bell')),
        Avatar({ size: 'sm' })
      )
    ),
    // Document body
    main({ class: css('_flex _col _overflow[auto] _p8') },
      ...children
    ),
    // Comment sidebar
    !asideCollapsed() ? section({ class: css('_flex _col _borderL _bgbg _overflow[auto]') },
      div({ class: css('_flex _aic _jcsb _p4 _borderB') },
        span({ class: css('_fontmedium') }, 'Comments'),
        Button({ variant: 'ghost', size: 'sm', onclick: () => setAsideCollapsed(true) },
          icon('x')
        )
      ),
      div({ class: css('_flex1 _p4 _overflow[auto]') },
        ...comments
      )
    ) : Button({
      variant: 'ghost',
      size: 'sm',
      class: css('_absolute _right4 _top[60px]'),
      onclick: () => setAsideCollapsed(false)
    }, icon('message-square'))
  );
}
